1	type Cell = [number, number]; // [x, y]
2	
3	export function nextGeneration(cells: Cell[]): Cell[] {
4	  const isAlive = (x: number, y: number): boolean =>
5	    cells.some(([cx, cy]) => cx === x && cy === y);
6	
7	  const countNeighbors = (x: number, y: number): number => {
8	    let count = 0;
9	    for (let dx = -1; dx <= 1; dx++) {
10	      for (let dy = -1; dy <= 1; dy++) {
11	        if (dx === 0 && dy === 0) continue;
12	        if (isAlive(x + dx, y + dy)) count++;
13	      }
14	    }
15	    return count;
16	  };
17	
18	  return cells.filter(([x, y]) => {
19	    const n = countNeighbors(x, y);
20	    return n === 2 || n === 3;
21	  });
22	}
